PROCEDURE SteamMethaneReforming(methaneInput, steamInput)
BEGIN
 SET temperature = 900 // Celsius
 SET pressure = 25 // bar

 // Step 1: Endothermic reforming reaction
 // CH4 + H2O → CO + 3H2
 syngas = REACT(methaneInput, steamInput, temperature, nickelCatalyst)

 hydrogenStage1 = syngas.hydrogen
 carbonMonoxide = syngas.carbonMonoxide

 // Step 2: Water gas shift reaction (exothermic)
 // CO + H2O → CO2 + H2
 hydrogenStage2 = WaterGasShift(carbonMonoxide, steamInput)

 // Combine hydrogen from both stages
 totalHydrogen = hydrogenStage1 + hydrogenStage2

 // Step 3: Separation and purification
 pureHydrogen = Purify(totalHydrogen)
 carbonDioxide = CaptureCO2(hydrogenStage2)

 RETURN (pureHydrogen, carbonDioxide)
END
